# Purpose: Load TPC-H data at scale factor 100 (SF100 ≈ 100 GB) into the tpch database
#          using the cpimport bulk loader for MariaDB ColumnStore.
#          Files are pipe-delimited .tbl files generated by dbgen.

cpimport tpch nation    /data/tpch/SF100/nation.tbl
cpimport tpch region    /data/tpch/SF100/region.tbl
cpimport tpch part      /data/tpch/SF100/part.tbl
cpimport tpch supplier  /data/tpch/SF100/supplier.tbl
cpimport tpch partsupp  /data/tpch/SF100/partsupp.tbl
cpimport tpch customer  /data/tpch/SF100/customer.tbl
cpimport tpch orders    /data/tpch/SF100/orders.tbl
cpimport tpch lineitem  /data/tpch/SF100/lineitem.tbl
